import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef
} from 'react';
import { Connection, clusterApiUrl, Keypair } from '@solana/web3.js';
import localforage from 'localforage';

const AppContext = createContext();

// Use localStorage only - skip IndexedDB entirely on mobile
localforage.config({
  name: 'nexus-app',
  storeName: 'wallets',
  description: 'Nexus wallet storage',
  driver: localforage.LOCALSTORAGE  // Force localStorage only
});

export function AppProvider({ children }) {
  const [network, setNetwork] = useState('devnet');
  const [connection, setConnection] = useState(null);
  const [wallets, setWallets] = useState([]);
  const [balances, setBalances] = useState({});
  const [deployedToken, setDeployedToken] = useState(null);
  const [logs, setLogs] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [loadError, setLoadError] = useState(null);

  const isMounted = useRef(true);
  const walletsRef = useRef(wallets);

  useEffect(() => {
    walletsRef.current = wallets;
  }, [wallets]);

  useEffect(() => {
    try {
      const conn = new Connection(clusterApiUrl(network), 'confirmed');
      setConnection(conn);
    } catch (err) {
      console.error('Failed to create connection:', err);
    }
  }, [network]);

  useEffect(() => {
    return () => {
      isMounted.current = false;
    };
  }, []);

  const addLog = useCallback((msg, type = 'info') => {
    if (!isMounted.current) return;
    setLogs(prev => [...prev, {
      msg,
      type,
      time: new Date().toLocaleTimeString()
    }]);
  }, []);

  const refreshBalances = useCallback(async () => {
    if (!connection || walletsRef.current.length === 0) return;

    try {
      const newBalances = {};
      const walletSnapshot = walletsRef.current;

      await Promise.all(
        walletSnapshot.map(async (w) => {
          try {
            const lamports = await connection.getBalance(w.keypair.publicKey);
            if (isMounted.current) {
              newBalances[w.publicKey] = lamports / 1000000000;
            }
          } catch (err) {
            console.error('Failed to fetch balance for', w.publicKey, err);
            newBalances[w.publicKey] = 0;
          }
        })
      );

      if (isMounted.current) {
        setBalances(newBalances);
      }
    } catch (err) {
      console.error('Balance fetch failed:', err);
      addLog('Failed to refresh balances', 'error');
    }
  }, [connection, addLog]);

  // CRITICAL FIX: Load data only once on mount, no dependencies that cause re-run
  useEffect(() => {
    let timeoutId;

    const loadData = async () => {
      try {
        console.log('Starting data load...');

        // Load wallets
        const savedWallets = await localforage.getItem('wallets');
        console.log('Wallets loaded:', savedWallets);

        if (savedWallets && Array.isArray(savedWallets) && isMounted.current) {
          const reconstructed = savedWallets.map((w, index) => {
            try {
              const keypair = Keypair.fromSecretKey(Uint8Array.from(w.secretKey));
              return {
                name: w.name || 'Wallet ' + (index + 1),
                publicKey: w.publicKey,
                keypair: keypair
              };
            } catch (err) {
              console.error('Failed to reconstruct wallet:', err);
              return null;
            }
          }).filter(Boolean);

          setWallets(reconstructed);
          console.log('Loaded', reconstructed.length, 'wallets');
        }

        // Load deployed token
        const savedToken = await localforage.getItem('deployedToken');
        if (savedToken && isMounted.current) {
          setDeployedToken(savedToken);
        }

        // Load logs
        const savedLogs = await localforage.getItem('logs');
        if (savedLogs && Array.isArray(savedLogs) && isMounted.current) {
          setLogs(savedLogs);
        } else if (isMounted.current) {
          setLogs([{
            msg: 'System initialized',
            type: 'success',
            time: new Date().toLocaleTimeString()
          }]);
        }

      } catch (err) {
        console.error('Failed to load data:', err);
        if (isMounted.current) {
          setLoadError(err.message);
          setLogs([{
            msg: 'System initialized (storage error)',
            type: 'warning',
            time: new Date().toLocaleTimeString()
          }]);
        }
      } finally {
        // ALWAYS set loading to false, no matter what
        setTimeout(() => {
          if (isMounted.current) {
            console.log('Setting isLoading to false');
            setIsLoading(false);
          }
        }, 500);
      }
    };

    // HARD TIMEOUT: Force finish after 8 seconds no matter what
    timeoutId = setTimeout(() => {
      console.log('HARD TIMEOUT: forcing load to complete');
      setIsLoading(false);
      setLoadError('Storage timeout');
    }, 8000);

    loadData();

    return () => clearTimeout(timeoutId);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // EMPTY DEPENDENCY ARRAY - only run once!

  useEffect(() => {
    if (wallets.length > 0 && connection) {
      refreshBalances();
      const interval = setInterval(refreshBalances, 30000);
      return () => clearInterval(interval);
    }
  }, [wallets.length, connection, refreshBalances]);

  useEffect(() => {
    const saveWallets = async () => {
      try {
        if (wallets.length === 0) {
          await localforage.removeItem('wallets');
        } else {
          const safeWallets = wallets.map(w => ({
            name: w.name,
            publicKey: w.publicKey,
            secretKey: Array.from(w.keypair.secretKey)
          }));
          await localforage.setItem('wallets', safeWallets);
        }
      } catch (err) {
        console.error('Failed to save wallets:', err);
        addLog('Failed to save wallets', 'error');
      }
    };

    if (!isLoading) saveWallets();
  }, [wallets, isLoading, addLog]);

  useEffect(() => {
    const saveToken = async () => {
      try {
        if (deployedToken) {
          await localforage.setItem('deployedToken', deployedToken);
        } else {
          await localforage.removeItem('deployedToken');
        }
      } catch (err) {
        console.error('Failed to save token:', err);
      }
    };

    if (!isLoading) saveToken();
  }, [deployedToken, isLoading]);

  useEffect(() => {
    const saveLogs = async () => {
      try {
        const trimmed = logs.slice(-100);
        await localforage.setItem('logs', trimmed);
      } catch (err) {
        console.error('Failed to save logs:', err);
      }
    };

    if (!isLoading && logs.length > 0) saveLogs();
  }, [logs, isLoading]);

  const addWallet = useCallback(async (name) => {
    try {
      const newKeypair = Keypair.generate();
      const newWallet = {
        name: name || 'Wallet ' + (wallets.length + 1),
        publicKey: newKeypair.publicKey.toString(),
        keypair: newKeypair
      };

      setWallets(prev => [...prev, newWallet]);
      addLog('Created wallet: ' + newWallet.publicKey.slice(0, 8) + '...', 'success');
      return newWallet;
    } catch (err) {
      console.error('Failed to create wallet:', err);
      addLog('Failed to create wallet', 'error');
      return null;
    }
  }, [wallets.length, addLog]);

  const importWallet = useCallback(async (name, secretKey) => {
    try {
      const secretKeyArray = secretKey instanceof Uint8Array
        ? secretKey
        : new Uint8Array(secretKey);

      const keypair = Keypair.fromSecretKey(secretKeyArray);
      const newWallet = {
        name: name || 'Imported ' + (wallets.length + 1),
        publicKey: keypair.publicKey.toString(),
        keypair: keypair
      };

      if (wallets.some(w => w.publicKey === newWallet.publicKey)) {
        addLog('Wallet already exists', 'warning');
        return null;
      }

      setWallets(prev => [...prev, newWallet]);
      addLog('Imported wallet: ' + newWallet.publicKey.slice(0, 8) + '...', 'success');
      return newWallet;
    } catch (err) {
      console.error('Failed to import wallet:', err);
      addLog('Failed to import wallet: ' + err.message, 'error');
      return null;
    }
  }, [wallets.length, wallets, addLog]);

  const removeWallet = useCallback((publicKey) => {
    setWallets(prev => prev.filter(w => w.publicKey !== publicKey));
    setBalances(prev => {
      const newBalances = { ...prev };
      delete newBalances[publicKey];
      return newBalances;
    });
    addLog('Wallet removed', 'info');
  }, [addLog]);

  const clearAllData = useCallback(async () => {
    try {
      await localforage.clear();
      setWallets([]);
      setBalances({});
      setDeployedToken(null);
      setLogs([{
        msg: 'All data cleared',
        type: 'info',
        time: new Date().toLocaleTimeString()
      }]);
    } catch (err) {
      console.error('Failed to clear data:', err);
      addLog('Failed to clear data', 'error');
    }
  }, [addLog]);

  const refreshWalletBalances = useCallback(() => {
    refreshBalances();
    addLog('Balances refreshed', 'info');
  }, [refreshBalances, addLog]);

  if (isLoading) {
    return (
      <div style={{ 
        padding: '20px', 
        textAlign: 'center',
        background: '#0a0a0f',
        color: '#00f3ff',
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center'
      }}>
        <h2>Loading Nexus...</h2>
        <p style={{ color: '#666', fontSize: '12px', marginTop: '10px' }}>
          {loadError ? 'Error: ' + loadError : 'Initializing storage...'}
        </p>
        <p style={{ color: '#333', fontSize: '10px', marginTop: '20px' }}>
          (Will timeout in 8 seconds if stuck)
        </p>
        {loadError && (
          <button 
            onClick={() => window.location.reload()}
            style={{
              marginTop: '20px',
              padding: '10px 20px',
              background: 'rgba(0, 243, 255, 0.2)',
              border: '1px solid #00f3ff',
              color: '#00f3ff',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        )}
      </div>
    );
  }

  return (
    <AppContext.Provider value={{
      network,
      setNetwork,
      connection,
      wallets,
      balances,
      setWallets,
      addWallet,
      importWallet,
      removeWallet,
      deployedToken,
      setDeployedToken,
      logs,
      addLog,
      clearAllData,
      refreshWalletBalances
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within AppProvider');
  }
  return context;
}
